if (! function_exists('file_appender')) {
    function file_appender($path, $text)
    {
        $path = $path ?? '';
        $text = $text ?? '';

        // Restrict to workspace
        $workspaceDir = getcwd() . DIRECTORY_SEPARATOR . 'storage' . DIRECTORY_SEPARATOR . 'agent' . DIRECTORY_SEPARATOR . 'workspace';
        $fullPath = realpath(dirname($workspaceDir . DIRECTORY_SEPARATOR . ltrim($path, '/' . DIRECTORY_SEPARATOR)));
